class.description:
Use [code skip-lint]GKLocalPlayer[/code] to inspect authentication flags and to fetch the local player's friends as shown in the "Players" section of [code skip-lint]GameCenterGuide.md[/code]. Every asynchronous call mirrors Apple's API and invokes your [code skip-lint]Callable[/code] with the requested data plus an optional error [code skip-lint]Variant[/code] (which contains a [code skip-lint]GKError[/code] on failure). Refer to Apple's documentation at [url=https://developer.apple.com/documentation/gamekit/gklocalplayer]Apple's GKLocalPlayer reference[/url] for platform-specific behavior.

Sample from the guide that fetches the local player when your scene loads:
[codeblocks]
[gdscript]
var game_center: GameCenterManager
var local: GKLocalPlayer

func _ready() -> void:
    game_center = GameCenterManager.new()
    local = game_center.local_player
    print("ONREADY: local, is auth: %s" % local.is_authenticated)
    print("ONREADY: local, player ID: %s" % local.game_player_id)
[/gdscript]
[/codeblocks]

Friends-related helpers mirror the snippets in the guide (assuming you stored the player reference in [code]local[/code]):
[codeblocks]
[gdscript]
# Loads the local player's friends list if access is granted.
local.load_friends(func(friends: Array[GKPlayer], error: Variant) -> void:
    if error:
        print(error)
    else:
        for friend in friends:
            print(friend.display_name)
)

# Loads players the local user can challenge.
local.load_challengeable_friends(func(friends: Array[GKPlayer], error: Variant) -> void:
    if error:
        print(error)
    else:
        for friend in friends:
            print(friend.display_name)
)

# Loads the friends or recent players list.
local.load_recent_friends(func(friends: Array[GKPlayer], error: Variant) -> void:
    if error:
        print(error)
    else:
        for friend in friends:
            print(friend.display_name)
)
[/gdscript]
[/codeblocks]
